<?php

namespace Database\Seeders;

use App\Models\Menu;
use App\Models\MenuGroup;
use App\Models\MenuItem;
use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;

class StagingMenuSeeder extends Seeder
{
    public function run(): void
    {
        $this->command?->info('Seeding menus from staging data...');

        DB::transaction(function () {
            // Disable foreign key checks temporarily
            DB::statement('SET FOREIGN_KEY_CHECKS=0');

            // Clear existing data
            MenuItem::query()->delete();
            MenuGroup::query()->delete();
            Menu::query()->delete();

            // Re-enable foreign key checks
            DB::statement('SET FOREIGN_KEY_CHECKS=1');

            // Seed menus
            $this->seedMenus();

            // Seed menu groups
            $this->seedMenuGroups();

            // Seed menu items
            $this->seedMenuItems();
        });

        $this->command?->info('Staging menu seeder completed successfully!');
    }

    private function seedMenus(): void
    {
        $menus = [
            ['id' => 1, 'name' => 'Admin Menu', 'machine_name' => 'admin', 'description' => 'Main navigation menu for administrators', 'active' => 1],
            ['id' => 2, 'name' => 'Federation Menu', 'machine_name' => 'federation', 'description' => 'Navigation menu for federation users', 'active' => 1],
            ['id' => 3, 'name' => 'Entity Menu', 'machine_name' => 'entity', 'description' => 'Navigation menu for entity administrators', 'active' => 1],
            ['id' => 4, 'name' => 'Individual Menu', 'machine_name' => 'individual', 'description' => 'Navigation menu for individual users', 'active' => 1],
        ];

        foreach ($menus as $menu) {
            Menu::create($menu);
        }

        $this->command?->info('  - Seeded ' . count($menus) . ' menus');
    }

