    private function seedMenuItems(): void
    {
        $items = $this->getMenuItemsData();

        // Sort items so parents are created before children
        $sortedItems = $this->sortItemsByParentDependency($items);

        foreach ($sortedItems as $item) {
            MenuItem::create($item);
        }

        $this->command?->info('  - Seeded ' . count($items) . ' menu items');
    }

    private function sortItemsByParentDependency(array $items): array
    {
        $sorted = [];
        $pending = $items;
        $insertedIds = [];

        // Keep iterating until all items are sorted
        while (count($pending) > 0) {
            $inserted = false;

            foreach ($pending as $key => $item) {
                // Item can be inserted if it has no parent or its parent was already inserted
                if ($item['parent_id'] === null || in_array($item['parent_id'], $insertedIds)) {
                    $sorted[] = $item;
                    $insertedIds[] = $item['id'];
                    unset($pending[$key]);
                    $inserted = true;
                }
            }

            // Prevent infinite loop if there are circular dependencies
            if (! $inserted && count($pending) > 0) {
                $this->command?->warn('Warning: Some menu items have unresolved parent dependencies');
                // Add remaining items anyway
                foreach ($pending as $item) {
                    $sorted[] = $item;
                }
                break;
            }
        }

        return $sorted;
    }

